                                                padding: '12px',
                                                borderRadius: '12px',
                                                border: 'none',
                                                background: o.status === 'Pending' ? '#2563eb' : '#64748b',
                                                color: 'white',
                                                fontWeight: '800',
                                                cursor: 'pointer',
                                                display: 'flex',
                                                alignItems: 'center',
                                                justifyContent: 'center',
                                                gap: '8px',
                                                transition: 'all 0.2s'
                                            }}
                                        >
                                            <FiDownload /> {o.status === 'Pending' ? 'Download & Ready to Ship' : 'Download Invoice'}
                                        </button>

                                        {getNextStatus() && (
                                            <button 
                                                className={`status-next-btn ${status}`}
