import { useEffect } from 'react';
import { FiShoppingBag, FiArrowRight, FiTrash2, FiMinus, FiPlus, FiChevronLeft } from 'react-icons/fi';
import { Link, useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { useCart } from '../context/CartContext';
import Footer from '../components/Footer';
import { getImageUrl } from '../apiConfig';
import '../styles/Cart.css';

const Cart = () => {
  const { cartItems, removeFromCart, updateQuantity, cartTotal } = useCart();
  const navigate = useNavigate();

  useEffect(() => {
    window.scrollTo(0, 0);
  }, []);

  if (cartItems.length === 0) {
    return (
      <>
        <div className="cart-page">
          <div className="container">
            <motion.div 
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              className="empty-cart-premium"
            >
              <div style={{ width: '120px', height: '120px', borderRadius: '50%', background: '#fff', color: 'var(--maroon)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '3.5rem', margin: '0 auto 30px', boxShadow: '0 10px 30px rgba(0,0,0,0.05)' }}>
                <FiShoppingBag />
              </div>
              <h2 style={{ fontSize: '2.5rem', fontWeight: '800', color: 'var(--text-dark)', marginBottom: '16px', fontFamily: 'Playfair Display, serif' }}>Your Bag is Empty</h2>
              <p style={{ fontSize: '1.2rem', color: 'var(--text-gray)', marginBottom: '40px', maxWidth: '500px', margin: '0 auto 40px', lineHeight: 1.6 }}>
                It looks like you haven't discovered your next favorite saree yet. Explore our latest arrivals today!
              </p>
              <Link to="/product" className="btn-checkout-premium" style={{ display: 'inline-flex', width: 'auto', padding: '18px 50px', textDecoration: 'none' }}>
                Start Shopping <FiArrowRight style={{ marginLeft: '10px' }} />
              </Link>
            </motion.div>
          </div>
        </div>
        <Footer />
      </>
    );
  }

  return (
    <>
      <div className="cart-page">
        <div className="container">
          <div className="cart-header">
            <button className="back-btn" onClick={() => navigate('/product')} style={{ marginBottom: '20px' }}>
              <FiChevronLeft /> Back to Shop
            </button>
            <h1>Shopping Bag</h1>
          </div>

          <div className="cart-container">
            {/* Left: Items List */}
            <div className="cart-items-list">
              <AnimatePresence>
                {cartItems.map((item) => (
                  <motion.div 
                    key={item._id} 
                    className="cart-item-premium"
                    initial={{ opacity: 0, x: -20 }}
                    animate={{ opacity: 1, x: 0 }}
                    exit={{ opacity: 0, scale: 0.95 }}
                    layout
                  >
                    <div className="cart-item-image">
                      <img 
                        src={getImageUrl(item.images && item.images.length > 0 ? item.images[0] : '')} 
                        alt={item.name} 
                      />
                    </div>
                    
                    <div className="cart-item-info">
                      <div className="cart-item-title">{item.name}</div>
                      <div className="cart-item-meta">Category: {item.category}</div>
                      <div className="cart-item-price-unit">₹{item.price.toLocaleString()}</div>
                    </div>

                    <div className="cart-item-ops">
                      <div className="premium-qty">
                        <button 
                          className="premium-qty-btn" 
                          onClick={() => updateQuantity(item._id, item.quantity - 1)}
                          disabled={item.quantity <= 1}
                        >
                          <FiMinus />
                        </button>
                        <span className="qty-val">{item.quantity}</span>
                        <button 
                          className="premium-qty-btn" 
                          onClick={() => updateQuantity(item._id, item.quantity + 1)}
                        >
                          <FiPlus />
                        </button>
                      </div>
                      
                      <button className="premium-remove" onClick={() => removeFromCart(item._id)}>
                        <FiTrash2 /> Remove
                      </button>
                    </div>
                  </motion.div>
                ))}
              </AnimatePresence>
            </div>

            {/* Right: Summary Card */}
            <motion.div 
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              className="cart-summary-premium"
            >
              <h2 className="summary-title-premium">Order Summary</h2>
              
              <div className="summary-details">
                <div className="detail-line">
                  <span>Subtotal ({cartItems.length} items)</span>
                  <span>₹{cartTotal.toLocaleString()}</span>
                </div>
                <div className="detail-line">
                  <span>Standard Delivery</span>
                  <span style={{ color: '#059669', fontWeight: 'bold' }}>FREE</span>
                </div>
                <div className="detail-line">
                  <span>Estimated Tax</span>
                  <span>₹0</span>
                </div>
                <div className="detail-line grand-total">
                  <span>Total Amount</span>
                  <span>₹{cartTotal.toLocaleString()}</span>
                </div>
              </div>

              <button className="btn-checkout-premium" onClick={() => navigate('/checkout')}>
                Secure Checkout
              </button>


              <div style={{ marginTop: '24px', textAlign: 'center' }}>
                <p style={{ fontSize: '0.85rem', color: 'var(--text-gray)', marginBottom: '15px' }}>
                  We accept all major credit cards and UPI.
                </p>
                <div style={{ display: 'flex', justifyContent: 'center', gap: '15px', color: '#cbd5e1', fontSize: '1.5rem' }}>
                  {/* Secure payment icons would go here */}
                </div>
              </div>
            </motion.div>
          </div>
        </div>
      </div>
      <Footer />
    </>
  );
};

export default Cart;

import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';

import { FiUser, FiMail, FiPhone, FiMapPin, FiArrowLeft, FiLock, FiCheckCircle } from 'react-icons/fi';
import { useCart } from '../context/CartContext';
import Footer from '../components/Footer';
import { API_BASE_URL, getImageUrl } from '../apiConfig';
import '../styles/Checkout.css';

const Checkout = () => {
  const navigate = useNavigate();
  const { cartItems, cartTotal } = useCart();
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    mobileNumber: '',
    address: ''
  });

  useEffect(() => {
    window.scrollTo(0, 0);
    const storedUser = localStorage.getItem('user');
    if (storedUser) {
      const user = JSON.parse(storedUser);
      setFormData({
        name: user.name || '',
        email: user.email || '',
        mobileNumber: user.mobileNumber || '',
        address: user.address || ''
      });
    } else {
      navigate('/login');
    }

    if (cartItems.length === 0) {
      navigate('/cart');
    }
  }, [navigate, cartItems.length]);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      // 1. Create order on backend
      const response = await fetch(`${API_BASE_URL}/api/payment/order`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          amount: cartTotal,
          currency: 'INR',
          receipt: `rcpt_${Date.now()}`
        })
      });

      const orderData = await response.json();

      if (!orderData.id) {
        alert('Failed to initiate payment. Please try again.');
        return;
      }

      // 2. Configure Razorpay
      const options = {
        key: 'rzp_test_SLcsBD1iGzuxTA', // Key provided by user
        amount: orderData.amount,
        currency: orderData.currency,
        name: "BHARTI GLOOMS",
        description: "Premium Ethnic Wear Purchase",
        order_id: orderData.id,
        handler: async function (response) {
          // Success! Verify on backend and save order
          const storedUser = JSON.parse(localStorage.getItem('user'));
          
          const orderDetails = {
            userId: storedUser?._id,
            name: formData.name,
            email: formData.email,
            mobileNumber: formData.mobileNumber,
            address: formData.address,
            products: cartItems,
            totalAmount: cartTotal
          };

          const verifyRes = await fetch(`${API_BASE_URL}/api/payment/verify`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
              razorpay_order_id: response.razorpay_order_id,
              razorpay_payment_id: response.razorpay_payment_id,
              razorpay_signature: response.razorpay_signature,
              orderDetails: orderDetails
            })
          });

          const verifyData = await verifyRes.json();

          if (verifyRes.ok) {
            // Redirect to Invoice on success
            navigate('/invoice', {
              state: {
                paymentId: response.razorpay_payment_id,
                orderData: orderData,
                formData: formData,
                cartItems: cartItems,
                totalAmount: cartTotal
              }
            });
          } else {
            alert('Payment verification failed: ' + verifyData.message);
          }
        },
        prefill: {
          name: formData.name,
          email: formData.email,
          contact: formData.mobileNumber
        },
        notes: {
          address: formData.address
        },
        theme: {
          color: "#800020" // Maroon theme
        }
      };

      const rzp1 = new window.Razorpay(options);
      rzp1.on('payment.failed', function (response) {
        alert("Payment Failed: " + response.error.description);
      });
      rzp1.open();

    } catch (error) {
      console.error('Payment Flow Error:', error);
      alert('An error occurred while processing your payment.');
    }
  };


  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.1
      }
    }
  };

  const itemVariants = {
    hidden: { opacity: 0, y: 20 },
    visible: { opacity: 1, y: 0 }
  };

  return (
    <>
      <div className="checkout-page">
        <div className="container">
          {/* Progress Indicator */}
          <div className="checkout-progress">
             <div className="progress-step completed"><span>1</span> Bag</div>
             <div className="progress-line active"></div>
             <div className="progress-step active"><span>2</span> Shipping</div>
             <div className="progress-line"></div>
             <div className="progress-step"><span>3</span> Payment</div>
          </div>

          <button className="back-link" onClick={() => navigate('/cart')}>
            <FiArrowLeft /> Back to Shopping Bag
          </button>

          <div className="checkout-grid">
            {/* Left: Shipping Form */}
            <motion.div 
              variants={containerVariants}
              initial="hidden"
              animate="visible"
              className="checkout-form-section"
            >
              <motion.h1 variants={itemVariants} className="checkout-title">Shipping Details</motion.h1>
              <motion.p variants={itemVariants} className="checkout-subtitle">Where should we send your exquisite selection?</motion.p>

              <form onSubmit={handleSubmit} className="premium-form">
                <motion.div variants={itemVariants} className="form-group-premium">
                  <label><FiUser /> Full Name</label>
                  <input
                    type="text"
                    name="name"
                    value={formData.name}
                    onChange={handleChange}
                    placeholder="Enter your full name"
                    required
                  />
                </motion.div>

                <motion.div variants={itemVariants} className="form-row-premium">
                  <div className="form-group-premium">
                    <label><FiMail /> Email Address</label>
                    <input
                      type="email"
                      name="email"
                      value={formData.email}
                      onChange={handleChange}
                      placeholder="name@example.com"
                      required
                    />
                  </div>
                  <div className="form-group-premium">
                    <label><FiPhone /> Mobile Number</label>
                    <input
                      type="tel"
                      name="mobileNumber"
                      value={formData.mobileNumber}
                      onChange={handleChange}
                      placeholder="Enter 10 digit number"
                      required
                    />
                  </div>
                </motion.div>

                <motion.div variants={itemVariants} className="form-group-premium">
                  <label><FiMapPin /> Delivery Address</label>
                  <textarea
                    name="address"
                    value={formData.address}
                    onChange={handleChange}
                    placeholder="Full house address, landmark, city, state, pincode"
                    required
                    rows="4"
                  ></textarea>
                </motion.div>


                <motion.div variants={itemVariants} className="payment-notice-premium">
                  <FiLock /> Your information is encrypted and processed securely.
                </motion.div>

                <motion.button 
