import { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { FiMail, FiPhone, FiMapPin, FiSend, FiClock } from 'react-icons/fi';
import axios from 'axios';
import Footer from '../components/Footer';
import { API_BASE_URL } from '../apiConfig';
import '../styles/Legal.css';

const ContactUs = () => {
  const [formData, setFormData] = useState({ name: '', email: '', subject: '', message: '' });
  const [submitted, setSubmitted] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  useEffect(() => {
    window.scrollTo(0, 0);
  }, []);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    console.log('📤 Submitting contact form...', formData);
    setLoading(true);
    setError(null);
    
    try {
      // Use dynamic API_BASE_URL for live deployment
      const response = await axios.post(`${API_BASE_URL}/api/complaints`, formData);
      
      console.log('✅ Submission successful:', response.data);
      setSubmitted(true);
      setFormData({ name: '', email: '', subject: '', message: '' });
    } catch (err) {
      console.error('❌ Contact Form Error:', err);
      const errorMsg = err.response?.data?.message || 'Failed to send message. Please check your connection.';
      setError(errorMsg);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="legal-page">
      <div className="legal-header">
        <motion.h1 
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity : 1, y : 0 }}
          transition={{ duration: 0.6 }}
        >
          Contact Us
