    setError('');
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      const res = await axios.post(`${API_BASE_URL}/api/auth/login`, formData);
      
      if (res.data.requires2FA) {
        setShow2FA(true);
        setSuccess(res.data.message);
        setLoading(false);
        return;
      }

      localStorage.setItem('token', res.data.token);
      localStorage.setItem('user', JSON.stringify(res.data.user));
      
      if (res.data.user.role === 'admin') {
        navigate('/admin/dashboard');
      } else {
        navigate('/');
      }
    } catch (err) {
      setError(err.response?.data?.message || 'Login failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const handle2FASubmit = async (e) => {
    if (e) e.preventDefault();
    const fullCode = twoFactorCode.join('');
    verifyOTP(fullCode);
  };

  const verifyOTP = async (code) => {
    if (code.length !== 6) {
      setError('Please enter a valid 6-digit code');
      return;
    }

    setLoading(true);
    setError('');

    try {
      const res = await axios.post(`${API_BASE_URL}/api/auth/admin/verify-2fa`, {
        email: formData.email,
        code: code
      });

      localStorage.setItem('token', res.data.token);
      localStorage.setItem('user', JSON.stringify(res.data.user));
      navigate('/admin/dashboard');
    } catch (err) {
      setError(err.response?.data?.message || 'Invalid 2FA code. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const handleOtpChange = (index, value) => {
    if (isNaN(value)) return;
    const newOtp = [...twoFactorCode];
    newOtp[index] = value.substring(value.length - 1);
    setTwoFactorCode(newOtp);

    // Auto focus next
    if (value && index < 5) {
      otpRefs[index + 1].current.focus();
    }

    // Auto submit on last digit
    if (value && index === 5) {
      const fullCode = newOtp.join('');
      if (fullCode.length === 6) {
        verifyOTP(fullCode);
      }
    }
  };

  const handleOtpKeyDown = (index, e) => {
    if (e.key === 'Backspace' && !twoFactorCode[index] && index > 0) {
      otpRefs[index - 1].current.focus();
    }
  };

  const handleOtpPaste = (e) => {
    const pasteData = e.clipboardData.getData('text').slice(0, 6).split('');
    if (pasteData.length === 6 && pasteData.every(char => !isNaN(char))) {
      setTwoFactorCode(pasteData);
      otpRefs[5].current.focus();
      verifyOTP(pasteData.join(''));
    }
  };

  const loginWithGoogle = useGoogleLogin({
    onSuccess: async (tokenResponse) => {
      setLoading(true);
      setError('');
      try {
        // Since we are using custom button, we get an access token
        // We might need to fetch user info from google or send the code to backend
        // For simplicity, let's assume our backend handles the token
        const res = await axios.post(`${API_BASE_URL}/api/auth/google-login`, {
          access_token: tokenResponse.access_token
        });
        localStorage.setItem('token', res.data.token);
        localStorage.setItem('user', JSON.stringify(res.data.user));
        
        if (res.data.user.role === 'admin') {
          navigate('/admin/dashboard');
        } else {
          navigate('/');
        }
      } catch (err) {
        console.error('Google login error:', err);
        setError(err.response?.data?.message || 'Google Login failed. Please try again.');
      } finally {
        setLoading(false);
      }
    },
    onError: (error) => {
      console.error('Google Login Popup Error:', error);
      setError('Google Sign-In was blocked or failed. Please check your browser settings and try again.');
    }
  });

  return (
    <>
      <div className="auth-page">
        <div className="auth-bg-1" />
        <div className="auth-bg-2" />

        <motion.div 
          className="auth-container"
          initial={{ opacity: 0, y: 30 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8, ease: [0.16, 1, 0.3, 1] }}
        >
          <div className="auth-form-panel">
            <div className="auth-form-header">
              <motion.h3
                initial={{ opacity: 0, y: -10 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: 0.3 }}
              >
                Welcome Back
              </motion.h3>
              <motion.p
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                transition={{ delay: 0.4 }}
              >
                Don't have an account? <Link to="/register" className="text-gradient" style={{ fontWeight: 700 }}>Create one now</Link>
              </motion.p>
            </div>

            {error && <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="alert-msg alert-error">⚠️ {error}</motion.div>}
            {success && <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="alert-msg alert-success">✅ {success}</motion.div>}

            <AnimatePresence mode="wait">
              {!show2FA ? (
                <motion.form 
                  key="login-form"
                  onSubmit={handleSubmit}
                  initial={{ opacity: 0, x: -20 }}
                  animate={{ opacity: 1, x: 0 }}
                  exit={{ opacity: 0, x: 20 }}
                >
                  <motion.div 
                    className="form-group"
                    initial={{ opacity: 0, x: -10 }}
                    animate={{ opacity: 1, x: 0 }}
                    transition={{ delay: 0.5 }}
                  >
                    <label className="form-label">Email Address</label>
                    <div className="form-input-wrapper">
                      <FiMail className="form-input-icon" />
                      <input
                        type="email"
                        name="email"
                        className="form-input"
                        placeholder="Enter your email"
                        value={formData.email}
                        onChange={handleChange}
                        required
                      />
                    </div>
                  </motion.div>

                  <motion.div 
                    className="form-group"
                    initial={{ opacity: 0, x: -10 }}
                    animate={{ opacity: 1, x: 0 }}
                    transition={{ delay: 0.6 }}
                  >
                    <label className="form-label">Password</label>
                    <div className="form-input-wrapper">
                      <FiLock className="form-input-icon" />
                      <input
                        type={showPassword ? 'text' : 'password'}
                        name="password"
                        className="form-input"
                        placeholder="Enter your password"
                        value={formData.password}
                        onChange={handleChange}
                        required
                      />
                      <button
                        type="button"
                        className="password-toggle"
                        onClick={() => setShowPassword(!showPassword)}
                      >
                        {showPassword ? <FiEyeOff /> : <FiEye />}
                      </button>
                    </div>
                    <div style={{ textAlign: 'right', marginTop: '10px' }}>
                      <Link to="/forgot-password" style={{ fontSize: '0.85rem', color: 'var(--maroon)', textDecoration: 'none', fontWeight: '700' }}>
                        Forgot Password?
                      </Link>
                    </div>
                  </motion.div>

                  <motion.button 
                    type="submit" 
                    className="form-submit-btn" 
                    disabled={loading}
                    whileHover={{ scale: 1.02 }}
                    whileTap={{ scale: 0.98 }}
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: 0.7 }}
                  >
                    {loading ? 'Signing In...' : 'Sign In'}
                  </motion.button>
                </motion.form>
              ) : (
                <motion.form 
                  key="2fa-form"
                  onSubmit={handle2FASubmit}
                  initial={{ opacity: 0, x: 20 }}
                  animate={{ opacity: 1, x: 0 }}
                  exit={{ opacity: 0, x: -20 }}
                >
                  <div className="otp-container">
                    <motion.div 
                      className="otp-header-icon"
                      initial={{ scale: 0.5, opacity: 0 }}
                      animate={{ scale: 1, opacity: 1 }}
                      transition={{ type: 'spring', stiffness: 200, damping: 15 }}
                    >
                      <FiShield />
                    </motion.div>
                    
                    <div className="otp-header-text" style={{ textAlign: 'center', marginBottom: '10px' }}>
                      <h4 style={{ color: 'var(--maroon)', fontSize: '1.2rem', fontWeight: 800, marginBottom: '5px' }}>Identity Verification</h4>
                      <p style={{ fontSize: '0.85rem', color: '#64748b' }}>Enter the 6-digit code from your app</p>
                    </div>

                    <div className="otp-input-row" onPaste={handleOtpPaste}>
                      {twoFactorCode.map((digit, index) => (
                        <input
                          key={index}
                          ref={otpRefs[index]}
                          type="text"
                          maxLength={1}
                          value={digit}
                          onChange={(e) => handleOtpChange(index, e.target.value)}
                          onKeyDown={(e) => handleOtpKeyDown(index, e)}
                          className={`otp-digit ${digit ? 'has-value' : ''} ${error ? 'error' : ''}`}
                          autoFocus={index === 0}
                        />
                      ))}
                    </div>

                    <div className="otp-help-text">
                      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px', color: '#94a3b8', fontSize: '0.8rem' }}>
                        <FiSmartphone />
                        <span>Check Google Authenticator</span>
                      </div>
                    </div>
                  </div>

                  <motion.button 
                    type="submit" 
                    className="form-submit-btn" 
                    disabled={loading}
                    whileHover={{ scale: 1.02 }}
                    whileTap={{ scale: 0.98 }}
                  >
                    {loading ? 'Verifying...' : 'Verify & Login'}
                  </motion.button>

                  <button 
                    type="button" 
                    onClick={() => setShow2FA(false)}
                    style={{ background: 'none', border: 'none', color: 'var(--maroon)', width: '100%', marginTop: '15px', cursor: 'pointer', fontWeight: 600 }}
                  >
                    Back to Password
                  </button>
                </motion.form>
              )}
            </AnimatePresence>

              <motion.div 
                className="auth-divider"
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                transition={{ delay: 0.8 }}
              >
                <span>OR</span>
              </motion.div>

              <motion.div 
                className="google-login-container"
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: 0.9 }}
              >
                <button 
                  type="button" 
                  className="custom-google-btn" 
                  onClick={() => loginWithGoogle()}
                  disabled={loading}
                >
                  <img src="https://www.gstatic.com/images/branding/product/1x/gsa_512dp.png" alt="Google" />
                  Continue with Google
                </button>
              </motion.div>
          </div>
        </motion.div>
      </div>
      <Footer />
    </>
  );
};

export default Login;

import { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { FiShoppingCart, FiArrowLeft, FiChevronLeft, FiChevronRight, FiHeart } from 'react-icons/fi';
import { motion, AnimatePresence } from 'framer-motion';
import axios from 'axios';
import { useCart } from '../context/CartContext';
import { useWishlist } from '../context/WishlistContext';
import Footer from '../components/Footer';
import { API_BASE_URL, getImageUrl } from '../apiConfig';
import '../styles/ProductDetails.css';

const ProductDetails = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const { addToCart } = useCart();
  const { toggleWishlist, isInWishlist } = useWishlist();
  const [product, setProduct] = useState(null);
  const [loading, setLoading] = useState(true);
  const [activeImage, setActiveImage] = useState(0);
  const [direction, setDirection] = useState(0);

  useEffect(() => {
    window.scrollTo(0, 0);
    fetchProduct();
  }, [id]);

  const fetchProduct = async () => {
    try {
      const res = await axios.get(`${API_BASE_URL}/api/admin/products/${id}`);
      setProduct(res.data);
    } catch (error) {
      console.error('Failed to fetch product details:', error);
    } finally {
      setLoading(false);
    }
  };

  const nextImage = () => {
    if (product.images && product.images.length > 0) {
      setDirection(1);
      setActiveImage((prev) => (prev + 1) % product.images.length);
    }
  };

  const prevImage = () => {
    if (product.images && product.images.length > 0) {
      setDirection(-1);
      setActiveImage((prev) => (prev - 1 + product.images.length) % product.images.length);
    }
  };

  const variants = {
    enter: (direction) => ({
      x: direction > 0 ? 300 : -300,
      opacity: 0
    }),
    center: {
      zIndex: 1,
      x: 0,
      opacity: 1
    },
    exit: (direction) => ({
      zIndex: 0,
      x: direction < 0 ? 300 : -300,
      opacity: 0
    })
  };

  if (loading) {
    return (
      <div className="loader-container">
        <div className="loader"></div>
      </div>
    );
  }

  if (!product) {
    return (
      <div className="error-container">
        <h2>Product not found</h2>
        <button onClick={() => navigate('/product')} className="btn-primary">
          Back to Shop
        </button>
      </div>
    );
  }

  return (
    <div className="product-details-page">
      <div className="container">
        <button className="back-btn" onClick={() => navigate(-1)}>
          <FiArrowLeft /> Back
        </button>

        <div className="details-grid">
          {/* Left: Image Slider */}
          <div className="details-images">
            <div className="main-image-wrapper">
              <AnimatePresence initial={false} custom={direction}>
                <motion.div
                  key={activeImage}
                  custom={direction}
                  variants={variants}
                  initial="enter"
                  animate="center"
                  exit="exit"
                  transition={{
                    x: { type: "spring", stiffness: 300, damping: 30 },
                    opacity: { duration: 0.2 }
                  }}
                  className="motion-image-container"
                >
                  <motion.img 
                    src={getImageUrl(product.images[activeImage])} 
                    alt={product.name} 
                    className="main-image"
                    whileHover={{ scale: 1.05 }}
                    transition={{ duration: 0.3 }}
                  />
                </motion.div>
              </AnimatePresence>
              
              {product.images && product.images.length > 1 && (
                <>
                  <button className="slider-nav prev" onClick={prevImage}>
                    <FiChevronLeft />
                  </button>
                  <button className="slider-nav next" onClick={nextImage}>
                    <FiChevronRight />
                  </button>
                  <div className="slider-dots">
                    {product.images.map((_, i) => (
                      <div 
                        key={i} 
                        className={`dot ${i === activeImage ? 'active' : ''}`}
                        onClick={() => {
                          setDirection(i > activeImage ? 1 : -1);
                          setActiveImage(i);
                        }}
                      />
                    ))}
                  </div>
                </>
              )}
            </div>
          </div>


          {/* Right: Product Info */}
          <div className="details-info">
            <div className="details-cat">{product.category}</div>
            <h1 className="details-title">{product.name}</h1>
            <div className="details-price">₹{product.price.toLocaleString()}</div>
            
            <div className="details-desc-section">
              <h3>Description</h3>
              <p>{product.description || 'Experience the elegance and comfort of this premium saree. Perfect for any special occasion.'}</p>
            </div>

            <div className="details-features">
              {product.specifications && Object.entries(product.specifications).map(([key, value]) => {
                if (!value || key === 'weightUnit') return null;
                
                let finalValue = value;
                if (key === 'weight' && product.specifications['weightUnit']) {
                  finalValue = `${value} ${product.specifications['weightUnit']}`;
                }

                return (
                  <div className="feature" key={key}>
                    <strong>{key.replace(/([A-Z])/g, ' $1').replace(/^./, str => str.toUpperCase())}:</strong> {finalValue}
                  </div>
                );
              })}
              <div className="feature">
                <strong>Category:</strong> {product.category}
              </div>
              <div className="feature">
                <strong>Brand:</strong> Bharti Glooms
              </div>

              {/* Stock Scarcity Alert */}
              {product.stock > 0 && product.stock < 5 && (
                <div className="stock-alert scarcity">
                  ⚠️ Hurry! Only {product.stock} items left in stock.
                </div>
              )}
              {product.stock === 0 && (
                <div className="stock-alert out-of-stock">
                  🚫 Currently Out of Stock.
                </div>
              )}
            </div>


            <div className="details-actions">
              <button 
                className="btn-add-to-cart" 
                onClick={() => {
                  addToCart(product);
                  navigate('/cart');
                }}
                disabled={product.stock <= 0}
              >
                <FiShoppingCart /> {product.stock <= 0 ? 'Out of Stock' : 'Add to Cart'}
              </button>
              <button 
                className={`btn-wishlist ${isInWishlist(product._id) ? 'active' : ''}`}
                onClick={() => toggleWishlist(product)}
              >
                <FiHeart fill={isInWishlist(product._id) ? "currentColor" : "none"} /> 
                {isInWishlist(product._id) ? ' Remove from Favorites' : ' Add to Favorites'}
              </button>
              <button className="btn-secondary-outline" onClick={() => navigate('/product')}>
                <FiArrowLeft /> Back to Collection
              </button>
            </div>

          </div>
        </div>
      </div>
      <Footer />
    </div>
  );
};

export default ProductDetails;

import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  FiUser, FiMail, FiPhone, FiLogOut, FiMapPin,
  FiShoppingBag, FiEdit2, FiLock, FiCheck, FiX,
  FiPackage, FiClock, FiTruck, FiCheckCircle
} from 'react-icons/fi';
import Footer from '../components/Footer';
import axios from 'axios';
import { API_BASE_URL } from '../apiConfig';

const statusIcon = (status) => {
  if (status === 'Pending') return <FiClock style={{ color: '#f39c12' }} />;
  if (status === 'Ready to Ship') return <FiPackage style={{ color: '#3498db' }} />;
  if (status === 'Out for Delivery') return <FiTruck style={{ color: '#9b59b6' }} />;
  if (status === 'Delivered') return <FiCheckCircle style={{ color: '#27ae60' }} />;
  return <FiClock />;
};

const statusColor = (status) => {
  if (status === 'Pending') return '#fff3cd';
  if (status === 'Ready to Ship') return '#cce5ff';
  if (status === 'Out for Delivery') return '#e8d5f5';
  if (status === 'Delivered') return '#d4edda';
  return '#f8f9fa';
};

const Profile = () => {
  const navigate = useNavigate();
  const [user, setUser] = useState(null);
  const [activeTab, setActiveTab] = useState('profile'); // 'profile' | 'orders'

  // Orders state
  const [orders, setOrders] = useState([]);
  const [ordersLoading, setOrdersLoading] = useState(false);

  // Edit flow state
  const [editMode, setEditMode] = useState(false);          // showing edit form
  const [passwordModal, setPasswordModal] = useState(false); // showing password modal
  const [passwordInput, setPasswordInput] = useState('');
  const [passwordError, setPasswordError] = useState('');
  const [passwordChecking, setPasswordChecking] = useState(false);
  const [saveLoading, setSaveLoading] = useState(false);
  const [editForm, setEditForm] = useState({ name: '', mobileNumber: '', address: '' });

  useEffect(() => {
    window.scrollTo(0, 0);
    const storedUser = localStorage.getItem('user');
    if (storedUser) {
      const u = JSON.parse(storedUser);
      setUser(u);
      setEditForm({ name: u.name || '', mobileNumber: u.mobileNumber || '', address: u.address || '' });
    } else {
      navigate('/login');
    }
  }, [navigate]);

  useEffect(() => {
    if (activeTab === 'orders' && user) fetchOrders();
  }, [activeTab, user]);

  const fetchOrders = async () => {
    setOrdersLoading(true);
    try {
      const userId = user.id || user._id;
      const email = user.email;
      const res = await axios.get(`${API_BASE_URL}/api/auth/my-orders?userId=${userId}&email=${email}`);
      setOrders(res.data);
    } catch (err) {
      console.error('Failed to fetch orders:', err);
    } finally {
      setOrdersLoading(false);
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    navigate('/login');
  };

  // Step 1: user clicks "Edit Profile" → show password modal
  const handleEditClick = () => {
    setPasswordModal(true);
    setPasswordInput('');
    setPasswordError('');
  };

  // Step 2: verify password
  const handlePasswordVerify = async () => {
    if (!passwordInput.trim()) { setPasswordError('Please enter your password'); return; }
    setPasswordChecking(true);
    setPasswordError('');
    try {
      const userId = user.id || user._id;
      await axios.post(`${API_BASE_URL}/api/auth/verify-password`, { userId, password: passwordInput });
      // Password correct — open edit form
      setPasswordModal(false);
      setEditMode(true);
    } catch (err) {
      setPasswordError(err.response?.data?.message || 'Incorrect password');
    } finally {
      setPasswordChecking(false);
    }
  };

  // Step 3: save updated profile
  const handleSaveProfile = async () => {
    setSaveLoading(true);
    try {
      const userId = user.id || user._id;
      const res = await axios.put(`${API_BASE_URL}/api/auth/update-profile`, {
        userId,
        name: editForm.name,
        mobileNumber: editForm.mobileNumber,
        address: editForm.address
      });
      const updatedUser = { ...user, ...res.data.user };
      setUser(updatedUser);
      localStorage.setItem('user', JSON.stringify(updatedUser));
      setEditMode(false);
    } catch (err) {
      alert('Failed to save profile');
    } finally {
      setSaveLoading(false);
    }
  };

  if (!user) return (
    <div style={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
      Loading...
    </div>
  );

  const infoCard = (icon, label, value) => (
    <div style={{
      padding: '18px 20px', borderRadius: '12px', border: '1px solid rgba(128,0,0,0.1)',
      background: 'var(--off-white)', display: 'flex', alignItems: 'center', gap: '16px'
    }}>
      <div style={{
        width: '44px', height: '44px', borderRadius: '10px',
        background: 'rgba(128,0,0,0.06)', color: 'var(--maroon)',
        display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '1.2rem', flexShrink: 0
      }}>{icon}</div>
      <div>
        <div style={{ fontSize: '0.8rem', color: 'var(--text-gray)', fontWeight: '600', marginBottom: '3px' }}>{label}</div>
        <div style={{ fontSize: '1rem', color: 'var(--text-dark)', fontWeight: '600' }}>{value || '—'}</div>
      </div>
    </div>
  );

  return (
    <>
      <div className="auth-page" style={{ padding: '100px 20px 60px' }}>
        <div className="auth-bg-1" />
        <div className="auth-bg-2" />

        <div style={{ maxWidth: '720px', margin: '0 auto' }}>

          {/* Avatar & Name */}
          <div style={{ textAlign: 'center', marginBottom: '30px' }}>
            <div style={{
              width: '80px', height: '80px', borderRadius: '50%',
              background: 'linear-gradient(135deg, var(--maroon), var(--maroon-light))',
              color: 'white', display: 'flex', alignItems: 'center', justifyContent: 'center',
              fontSize: '2.5rem', fontWeight: '800', margin: '0 auto 12px',
              boxShadow: '0 10px 25px rgba(128, 0, 0, 0.2)'
            }}>
              {user.name?.charAt(0).toUpperCase()}
            </div>
            <h2 style={{ margin: '0 0 4px', fontSize: '1.6rem', color: 'var(--text-dark)' }}>{user.name}</h2>
            <p style={{ margin: 0, color: 'var(--text-gray)', fontSize: '0.9rem' }}>{user.email}</p>
          </div>

          {/* Tabs */}
          <div style={{
            display: 'flex', gap: '8px', background: '#f8f5f2',
            padding: '6px', borderRadius: '14px', marginBottom: '24px'
          }}>
            {[
              { key: 'profile', label: 'My Profile', icon: <FiUser /> },
              { key: 'orders', label: 'My Orders', icon: <FiShoppingBag /> }
            ].map(tab => (
              <button key={tab.key} onClick={() => setActiveTab(tab.key)} style={{
                flex: 1, padding: '12px', borderRadius: '10px', border: 'none', cursor: 'pointer',
                display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px',
                fontWeight: '700', fontSize: '0.95rem', transition: 'all 0.2s',
                background: activeTab === tab.key ? 'var(--maroon)' : 'transparent',
                color: activeTab === tab.key ? 'white' : 'var(--text-gray)',
                boxShadow: activeTab === tab.key ? '0 4px 12px rgba(128,0,0,0.2)' : 'none'
              }}>
                {tab.icon} {tab.label}
              </button>
            ))}
          </div>

          {/* ── My Profile Tab ── */}
          {activeTab === 'profile' && (
            <div style={{
              background: 'white', borderRadius: '20px', padding: '30px',
              boxShadow: '0 4px 20px rgba(0,0,0,0.06)'
            }}>
              {!editMode ? (
                <>
                  <div style={{ display: 'flex', flexDirection: 'column', gap: '14px', marginBottom: '28px' }}>
                    {infoCard(<FiUser />, 'Full Name', user.name)}
                    {infoCard(<FiMail />, 'Email Address', user.email)}
                    {infoCard(<FiPhone />, 'Mobile Number', user.mobileNumber)}
                    {infoCard(<FiMapPin />, 'Delivery Address', user.address)}
                  </div>
                  <div style={{ display: 'flex', gap: '12px' }}>
                    <button onClick={handleEditClick} style={{
                      flex: 1, padding: '14px', borderRadius: '12px', border: 'none', cursor: 'pointer',
                      background: 'linear-gradient(135deg, var(--maroon), var(--maroon-light))',
                      color: 'white', fontWeight: '700', fontSize: '1rem',
                      display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px',
                      boxShadow: '0 4px 15px rgba(128,0,0,0.25)'
                    }}>
                      <FiEdit2 /> Edit Profile
                    </button>
                    <button onClick={handleLogout} style={{
                      padding: '14px 20px', borderRadius: '12px', cursor: 'pointer',
                      background: 'transparent', color: '#e74c3c',
                      border: '2px solid #e74c3c', fontWeight: '700', fontSize: '1rem',
                      display: 'flex', alignItems: 'center', gap: '8px'
                    }}>
                      <FiLogOut /> Sign Out
                    </button>
                  </div>
                </>
              ) : (
                /* Edit Form */
                <>
                  <h3 style={{ margin: '0 0 20px', color: 'var(--maroon)', display: 'flex', alignItems: 'center', gap: '8px' }}>
                    <FiEdit2 /> Edit Profile
                  </h3>
                  <div style={{ display: 'flex', flexDirection: 'column', gap: '16px', marginBottom: '24px' }}>
                    {[
                      { label: 'Full Name', key: 'name', type: 'text', placeholder: 'Your full name' },
                      { label: 'Mobile Number', key: 'mobileNumber', type: 'tel', placeholder: '10-digit number' },
                    ].map(field => (
                      <div key={field.key}>
                        <label style={{ fontSize: '0.85rem', fontWeight: '700', color: 'var(--text-gray)', marginBottom: '6px', display: 'block' }}>{field.label}</label>
                        <input
                          type={field.type}
                          value={editForm[field.key]}
                          onChange={e => setEditForm({ ...editForm, [field.key]: e.target.value })}
                          placeholder={field.placeholder}
                          style={{
                            width: '100%', padding: '12px 16px', borderRadius: '10px',
                            border: '1.5px solid rgba(128,0,0,0.2)', fontSize: '1rem',
                            outline: 'none', boxSizing: 'border-box'
                          }}
                        />
                      </div>
                    ))}
                    <div>
                      <label style={{ fontSize: '0.85rem', fontWeight: '700', color: 'var(--text-gray)', marginBottom: '6px', display: 'block' }}>Delivery Address</label>
                      <textarea
                        rows={3}
                        value={editForm.address}
                        onChange={e => setEditForm({ ...editForm, address: e.target.value })}
                        placeholder="Full address with landmark, city, state, pincode"
                        style={{
                          width: '100%', padding: '12px 16px', borderRadius: '10px',
                          border: '1.5px solid rgba(128,0,0,0.2)', fontSize: '1rem',
                          resize: 'vertical', outline: 'none', boxSizing: 'border-box'
                        }}
                      />
                    </div>
                  </div>
                  <div style={{ display: 'flex', gap: '12px' }}>
                    <button onClick={handleSaveProfile} disabled={saveLoading} style={{
                      flex: 1, padding: '14px', borderRadius: '12px', border: 'none', cursor: 'pointer',
                      background: 'linear-gradient(135deg, #27ae60, #2ecc71)',
                      color: 'white', fontWeight: '700', fontSize: '1rem',
                      display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px'
                    }}>
                      <FiCheck /> {saveLoading ? 'Saving...' : 'Save Changes'}
                    </button>
                    <button onClick={() => setEditMode(false)} style={{
                      padding: '14px 20px', borderRadius: '12px', cursor: 'pointer',
                      background: 'transparent', color: '#888',
                      border: '2px solid #ddd', fontWeight: '700',
                      display: 'flex', alignItems: 'center', gap: '8px'
                    }}>
                      <FiX /> Cancel
                    </button>
                  </div>
                </>
              )}
            </div>
          )}

          {/* ── My Orders Tab ── */}
          {activeTab === 'orders' && (
            <div>
              {ordersLoading ? (
                <div style={{ textAlign: 'center', padding: '60px', color: 'var(--text-gray)', fontSize: '1rem' }}>
                  Loading your orders...
                </div>
              ) : orders.length === 0 ? (
                <div style={{
                  textAlign: 'center', padding: '60px 20px', background: 'white',
                  borderRadius: '20px', boxShadow: '0 4px 20px rgba(0,0,0,0.06)'
                }}>
                  <div style={{ fontSize: '3rem', marginBottom: '12px' }}>🛍️</div>
                  <h3 style={{ color: 'var(--text-dark)', margin: '0 0 8px' }}>No orders yet</h3>
                  <p style={{ color: 'var(--text-gray)', margin: '0 0 20px' }}>Start shopping to see your orders here</p>
                  <button onClick={() => navigate('/product')} style={{
                    padding: '12px 28px', borderRadius: '12px', border: 'none', cursor: 'pointer',
                    background: 'var(--maroon)', color: 'white', fontWeight: '700'
                  }}>
                    Browse Collection
                  </button>
                </div>
              ) : (
                <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
                  {orders.map(order => (
                    <div key={order._id} style={{
                      background: 'white', borderRadius: '16px', padding: '20px',
                      boxShadow: '0 4px 15px rgba(0,0,0,0.06)',
                      borderLeft: '4px solid var(--maroon)'
                    }}>
                      {/* Order Header */}
                      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '14px', flexWrap: 'wrap', gap: '8px' }}>
                        <div>
                          <div style={{ fontWeight: '800', color: 'var(--maroon)', fontSize: '1rem' }}>
                            #{order._id?.slice(-8).toUpperCase()}
                          </div>
                          <div style={{ fontSize: '0.8rem', color: 'var(--text-gray)', marginTop: '2px' }}>
                            {new Date(order.createdAt).toLocaleDateString('en-IN', { day: 'numeric', month: 'long', year: 'numeric' })}
                          </div>
                        </div>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
                          {statusIcon(order.status)}
                          <span style={{
                            padding: '5px 14px', borderRadius: '20px', fontSize: '0.82rem',
                            fontWeight: '700', background: statusColor(order.status)
                          }}>
                            {order.status}
                          </span>
                        </div>
                      </div>

                      {/* Items */}
                      <div style={{ display: 'flex', flexDirection: 'column', gap: '10px', marginBottom: '14px' }}>
                        {order.products?.map((item, idx) => (
                          <div key={idx} style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                            {item.photo && (
                              <img src={item.photo} alt={item.name}
                                style={{ width: '48px', height: '48px', objectFit: 'cover', borderRadius: '8px', border: '1px solid #f0e8e8' }}
                                onError={e => e.target.style.display = 'none'}
                              />
                            )}
                            <div style={{ flex: 1 }}>
                              <div style={{ fontWeight: '700', color: 'var(--text-dark)', fontSize: '0.9rem' }}>{item.name}</div>
                              <div style={{ color: 'var(--text-gray)', fontSize: '0.8rem' }}>
                                ₹{item.price?.toLocaleString()} × {item.quantity}
                              </div>
                            </div>
                            <div style={{ fontWeight: '800', color: 'var(--maroon)', fontSize: '0.9rem' }}>
                              ₹{(item.price * item.quantity)?.toLocaleString()}
                            </div>
                          </div>
                        ))}
                      </div>

                      {/* Order Footer */}
                      <div style={{
                        display: 'flex', justifyContent: 'space-between', alignItems: 'center',
                        borderTop: '1px solid #f0e8e8', paddingTop: '12px', flexWrap: 'wrap', gap: '8px'
                      }}>
                        <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
                          <div style={{ fontSize: '0.82rem', color: 'var(--text-gray)' }}>
                            Payment: <strong>{order.payment?.method || 'N/A'}</strong>
                          </div>
                          <div style={{ fontWeight: '800', color: 'var(--text-dark)', fontSize: '1rem' }}>
                            Total: <span style={{ color: 'var(--maroon)' }}>₹{order.totalAmount?.toLocaleString()}</span>
                          </div>
                        </div>
                        <button 
                          onClick={() => navigate('/invoice', { 
                            state: {
                              paymentId: order.payment?.transactionId || order.payment?.orderId || 'SUCCESS',
                              orderData: { id: order._id },
                              formData: order.customer || user,
                              cartItems: order.products,
                              totalAmount: order.totalAmount
                            }
                          })}
                          style={{
                            padding: '10px 20px', borderRadius: '8px', border: '1px solid var(--maroon)',
                            background: 'white', color: 'var(--maroon)', fontWeight: '700', cursor: 'pointer',
                            transition: 'all 0.3s'
                          }}
                          onMouseEnter={(e) => { e.target.style.background = 'var(--maroon)'; e.target.style.color = 'white'; }}
                          onMouseLeave={(e) => { e.target.style.background = 'white'; e.target.style.color = 'var(--maroon)'; }}
                        >
                          View Details
                        </button>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}
        </div>
      </div>

      {/* Password Verification Modal */}
      {passwordModal && (
        <div style={{
          position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)',
          display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 9999, padding: '20px'
        }}>
          <div style={{
            background: 'white', borderRadius: '20px', padding: '35px',
            maxWidth: '420px', width: '100%', boxShadow: '0 20px 60px rgba(0,0,0,0.2)'
          }}>
            <div style={{ textAlign: 'center', marginBottom: '24px' }}>
              <div style={{
                width: '60px', height: '60px', borderRadius: '50%',
                background: 'rgba(128,0,0,0.08)', color: 'var(--maroon)',
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                fontSize: '1.6rem', margin: '0 auto 12px'
              }}>
                <FiLock />
              </div>
              <h3 style={{ margin: '0 0 6px', color: 'var(--text-dark)' }}>Verify Your Identity</h3>
              <p style={{ margin: 0, color: 'var(--text-gray)', fontSize: '0.9rem' }}>Enter your password to edit your profile</p>
            </div>

            <input
              type="password"
              placeholder="Enter your password"
              value={passwordInput}
              onChange={e => { setPasswordInput(e.target.value); setPasswordError(''); }}
              onKeyDown={e => e.key === 'Enter' && handlePasswordVerify()}
              autoFocus
              style={{
                width: '100%', padding: '13px 16px', borderRadius: '10px',
                border: `1.5px solid ${passwordError ? '#e74c3c' : 'rgba(128,0,0,0.2)'}`,
                fontSize: '1rem', outline: 'none', marginBottom: '8px', boxSizing: 'border-box'
              }}
            />
            {passwordError && (
              <p style={{ color: '#e74c3c', fontSize: '0.85rem', margin: '0 0 12px' }}>{passwordError}</p>
            )}

            <div style={{ display: 'flex', gap: '10px', marginTop: '16px' }}>
              <button onClick={handlePasswordVerify} disabled={passwordChecking} style={{
                flex: 1, padding: '13px', borderRadius: '10px', border: 'none', cursor: 'pointer',
                background: 'linear-gradient(135deg, var(--maroon), var(--maroon-light))',
                color: 'white', fontWeight: '700', fontSize: '0.95rem'
              }}>
                {passwordChecking ? 'Verifying...' : 'Confirm'}
              </button>
              <button onClick={() => setPasswordModal(false)} style={{
                padding: '13px 18px', borderRadius: '10px', cursor: 'pointer',
                background: 'transparent', border: '2px solid #ddd', color: '#888', fontWeight: '700'
              }}>
                Cancel
              </button>
            </div>
          </div>
        </div>
      )}

      <Footer />
    </>
  );
};

export default Profile;

import { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { FiUser, FiMail, FiPhone, FiLock, FiEye, FiEyeOff, FiMapPin } from 'react-icons/fi';
import axios from 'axios';
import { useGoogleLogin } from '@react-oauth/google';
import Footer from '../components/Footer';
import { API_BASE_URL } from '../apiConfig';
import '../styles/Auth.css';

const Register = () => {
  const navigate = useNavigate();
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    mobileNumber: '',
    address: '',
    password: '',
  });

  useEffect(() => {
    console.log('Register page mounted');
    window.scrollTo(0, 0);
  }, []);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
    setError('');
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      const res = await axios.post(`${API_BASE_URL}/api/auth/register`, formData);
      localStorage.setItem('token', res.data.token);
      localStorage.setItem('user', JSON.stringify(res.data.user));
      navigate('/');
    } catch (err) {
      setError(err.response?.data?.message || 'Registration failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const loginWithGoogle = useGoogleLogin({
    onSuccess: async (tokenResponse) => {
      setLoading(true);
      setError('');
      try {
        const res = await axios.post(`${API_BASE_URL}/api/auth/google-login`, {
          access_token: tokenResponse.access_token
        });
        localStorage.setItem('token', res.data.token);
        localStorage.setItem('user', JSON.stringify(res.data.user));
        
        if (res.data.user.role === 'admin') {
          navigate('/admin/dashboard');
        } else {
          navigate('/');
        }
      } catch (err) {
        console.error('Google login error:', err);
        setError(err.response?.data?.message || 'Google Login failed. Please try again.');
      } finally {
        setLoading(false);
      }
    },
    onError: (error) => {
      console.error('Google Register Popup Error:', error);
      setError('Google Sign-In failed or was blocked. Ensure your browser allows popups.');
    }
  });

  return (
    <>
      <div className="auth-page">
        <div className="auth-bg-1" />
        <div className="auth-bg-2" />

        <motion.div 
          className="auth-container"
          initial={{ opacity: 0, y: 30 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8, ease: [0.16, 1, 0.3, 1] }}
        >
          <div className="auth-form-panel">
            <div className="auth-form-header">
              <motion.h3
                initial={{ opacity: 0, y: -10 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: 0.3 }}
              >
                Create Account
              </motion.h3>
              <motion.p
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                transition={{ delay: 0.4 }}
              >
                Already have an account? <Link to="/login" className="text-gradient" style={{ fontWeight: 700 }}>Sign In</Link>
              </motion.p>
            </div>

            {error && <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="alert-msg alert-error">⚠️ {error}</motion.div>}
            {success && <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="alert-msg alert-success">✅ {success}</motion.div>}

            <form onSubmit={handleSubmit}>
              <motion.div 
                className="form-group"
                initial={{ opacity: 0, x: -10 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ delay: 0.5 }}
              >
                <label className="form-label">Full Name</label>
                <div className="form-input-wrapper">
                  <FiUser className="form-input-icon" />
                  <input
                    type="text"
                    name="name"
                    className="form-input"
                    placeholder="Enter your full name"
                    value={formData.name}
                    onChange={handleChange}
                    required
                  />
                </div>
              </motion.div>

              <motion.div 
                className="form-group"
                initial={{ opacity: 0, x: -10 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ delay: 0.6 }}
              >
                <label className="form-label">Email Address</label>
                <div className="form-input-wrapper">
                  <FiMail className="form-input-icon" />
                  <input
                    type="email"
                    name="email"
                    className="form-input"
                    placeholder="Enter your email"
                    value={formData.email}
                    onChange={handleChange}
                    required
                  />
                </div>
              </motion.div>

              <motion.div 
                className="form-group"
                initial={{ opacity: 0, x: -10 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ delay: 0.7 }}
              >
                <label className="form-label">Mobile Number</label>
                <div className="form-input-wrapper">
                  <FiPhone className="form-input-icon" />
                  <input
                    type="tel"
                    name="mobileNumber"
                    className="form-input"
                    placeholder="Enter mobile number"
                    value={formData.mobileNumber}
                    onChange={handleChange}
                    required
                  />
                </div>
              </motion.div>

              <motion.div 
                className="form-group"
                initial={{ opacity: 0, x: -10 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ delay: 0.8 }}
              >
                <label className="form-label">Password</label>
                <div className="form-input-wrapper">
                  <FiLock className="form-input-icon" />
                  <input
                    type={showPassword ? 'text' : 'password'}
                    name="password"
                    className="form-input"
                    placeholder="Create password"
                    value={formData.password}
                    onChange={handleChange}
                    required
                    minLength="6"
                  />
                  <button
                    type="button"
                    className="password-toggle"
                    onClick={() => setShowPassword(!showPassword)}
                  >
                    {showPassword ? <FiEyeOff /> : <FiEye />}
                  </button>
                </div>
              </motion.div>

              <motion.div 
                className="form-group"
                initial={{ opacity: 0, x: -10 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ delay: 0.9 }}
              >
                <label className="form-label">Full Address</label>
                <div className="form-input-wrapper">
                  <FiMapPin className="form-input-icon" style={{ top: '24px', transform: 'none' }} />
                  <textarea
                    name="address"
                    className="form-input"
                    placeholder="Enter your delivery address"
                    value={formData.address}
                    onChange={handleChange}
                    required
                    rows="2"
                    style={{ resize: 'none', paddingTop: '16px' }}
                  />
                </div>
              </motion.div>

              <motion.button 
                type="submit" 
                className="form-submit-btn" 
                disabled={loading}
                whileHover={{ scale: 1.02 }}
                whileTap={{ scale: 0.98 }}
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: 1.0 }}
              >
                {loading ? 'Creating Account...' : 'Create Account'}
              </motion.button>

              <motion.div 
                className="auth-divider"
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                transition={{ delay: 1.1 }}
              >
                <span>OR</span>
              </motion.div>

              <motion.div 
                className="google-login-container"
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: 1.2 }}
              >
                <button 
                  type="button" 
                  className="custom-google-btn" 
                  onClick={() => loginWithGoogle()}
                  disabled={loading}
                >
                  <img src="https://www.gstatic.com/images/branding/product/1x/gsa_512dp.png" alt="Google" />
                  Continue with Google
                </button>
              </motion.div>
              
              <motion.p 
                style={{ fontSize: '0.8rem', color: 'var(--text-gray)', textAlign: 'center', marginTop: '20px', lineHeight: 1.5 }}
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                transition={{ delay: 1.3 }}
              >
                By registering, you agree to Bharti Glooms' <br />
                <a href="#" style={{ color: 'var(--maroon)', fontWeight: '700' }}>Terms of Service</a> and <a href="#" style={{ color: 'var(--maroon)', fontWeight: '700' }}>Privacy Policy</a>.
              </motion.p>
            </form>
          </div>
        </motion.div>
      </div>
      <Footer />
    </>
  );
};

export default Register;

